sub execute_query {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth;
    eval {
        $sth = $dbh->prepare($sql);
        $sth->execute(@bind_params);
    };
    if ($@) {
        croak "Query execution failed: $@";
    }

    return $sth;
}

sub fetch_all_rows {
